import { useNavigate } from "react-router-dom";
import { useState,useEffect } from "react";
import axios from "axios";
import config from "../config.json";
import { toast } from "react-toastify";

function MiniUser() {
  const navigate = useNavigate()

  const [photo, setPhoto] = useState(null);
  const [data, setData] = useState(null);

  useEffect(() => {
  const fetchUserAndAvatar = async () => {
    try {
      // 1. Получаем пользователя
      const userResponse = await axios.get(
        config.BaseURL + "/users/me",
        { withCredentials: true }
      );

      setData(userResponse.data);

      const userId = userResponse.data.id;

      // 2. Получаем аватар
      const avatarResponse = await axios.get(
  `${config.BaseURL}/users/${userId}/avatar`,
  { withCredentials: true }
);

  setPhoto(avatarResponse.data.url);

    } catch (error) {
      toast.error("Ошибка при загрузке данных пользователя");
    }
  };
  fetchUserAndAvatar();

}, []);

  return (
    <div className="mini-user" onClick={()=>navigate("/settings/profile")}>
      <img src={photo} alt="" />
    </div>
  );
}

export default MiniUser;
